"use client"

import type React from "react"

import { useState, useRef, useEffect } from "react"
import { Play, Pause, Volume2, VolumeX, Maximize, Minimize, SkipBack, SkipForward, Settings } from "lucide-react"
import { cn } from "@/lib/utils"
import { Slider } from "@/components/ui/slider"
import { Button } from "@/components/ui/button"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"

interface VideoPlayerProps {
  src: string
  poster?: string
  title?: string
  primaryColor?: string
  secondaryColor?: string
}

export default function VideoPlayer({
  src = "https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4",
  poster = "/modern-video-player.png",
  title = "Big Buck Bunny",
  primaryColor = "#6d28d9",
  secondaryColor = "#4c1d95",
}: VideoPlayerProps) {
  const [isPlaying, setIsPlaying] = useState(false)
  const [volume, setVolume] = useState(1)
  const [isMuted, setIsMuted] = useState(false)
  const [currentTime, setCurrentTime] = useState(0)
  const [duration, setDuration] = useState(0)
  const [isFullscreen, setIsFullscreen] = useState(false)
  const [showControls, setShowControls] = useState(true)
  const [controlsTimeout, setControlsTimeout] = useState<NodeJS.Timeout | null>(null)
  const [primaryColorState, setPrimaryColorState] = useState(primaryColor)
  const [secondaryColorState, setSecondaryColorState] = useState(secondaryColor)
  const [isBuffering, setIsBuffering] = useState(false)
  const [hoverPosition, setHoverPosition] = useState<number | null>(null)
  const [previewTime, setPreviewTime] = useState<number | null>(null)

  const videoRef = useRef<HTMLVideoElement>(null)
  const playerRef = useRef<HTMLDivElement>(null)
  const progressRef = useRef<HTMLDivElement>(null)

  // Format time in MM:SS format
  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60)
    const seconds = Math.floor(time % 60)
    return `${minutes.toString().padStart(2, "0")}:${seconds.toString().padStart(2, "0")}`
  }

  // Handle play/pause
  const togglePlay = () => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.pause()
      } else {
        videoRef.current.play()
      }
      setIsPlaying(!isPlaying)
    }
  }

  // Handle volume change
  const handleVolumeChange = (value: number[]) => {
    if (videoRef.current) {
      const newVolume = value[0]
      videoRef.current.volume = newVolume
      setVolume(newVolume)
      setIsMuted(newVolume === 0)
    }
  }

  // Handle mute toggle
  const toggleMute = () => {
    if (videoRef.current) {
      if (isMuted) {
        videoRef.current.volume = volume
        setIsMuted(false)
      } else {
        videoRef.current.volume = 0
        setIsMuted(true)
      }
    }
  }

  // Handle seeking
  const handleSeek = (value: number[]) => {
    if (videoRef.current) {
      const newTime = value[0]
      videoRef.current.currentTime = newTime
      setCurrentTime(newTime)
    }
  }

  // Handle progress bar hover
  const handleProgressHover = (e: React.MouseEvent<HTMLDivElement>) => {
    if (progressRef.current && duration) {
      const rect = progressRef.current.getBoundingClientRect()
      const position = (e.clientX - rect.left) / rect.width
      setHoverPosition(position)
      setPreviewTime(position * duration)
    }
  }

  const handleProgressLeave = () => {
    setHoverPosition(null)
    setPreviewTime(null)
  }

  // Handle fullscreen toggle
  const toggleFullscreen = () => {
    if (playerRef.current) {
      if (!isFullscreen) {
        if (playerRef.current.requestFullscreen) {
          playerRef.current.requestFullscreen()
        }
      } else {
        if (document.exitFullscreen) {
          document.exitFullscreen()
        }
      }
      setIsFullscreen(!isFullscreen)
    }
  }

  // Skip forward/backward
  const skip = (seconds: number) => {
    if (videoRef.current) {
      videoRef.current.currentTime += seconds
    }
  }

  // Handle mouse movement to show/hide controls
  const handleMouseMove = () => {
    setShowControls(true)

    if (controlsTimeout) {
      clearTimeout(controlsTimeout)
    }

    const timeout = setTimeout(() => {
      if (isPlaying) {
        setShowControls(false)
      }
    }, 3000)

    setControlsTimeout(timeout)
  }

  // Update time
  useEffect(() => {
    const video = videoRef.current

    const handleTimeUpdate = () => {
      if (video) {
        setCurrentTime(video.currentTime)
      }
    }

    const handleLoadedMetadata = () => {
      if (video) {
        setDuration(video.duration)
      }
    }

    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement)
    }

    const handleWaiting = () => {
      setIsBuffering(true)
    }

    const handlePlaying = () => {
      setIsBuffering(false)
    }

    if (video) {
      video.addEventListener("timeupdate", handleTimeUpdate)
      video.addEventListener("loadedmetadata", handleLoadedMetadata)
      video.addEventListener("waiting", handleWaiting)
      video.addEventListener("playing", handlePlaying)
      document.addEventListener("fullscreenchange", handleFullscreenChange)
    }

    return () => {
      if (video) {
        video.removeEventListener("timeupdate", handleTimeUpdate)
        video.removeEventListener("loadedmetadata", handleLoadedMetadata)
        video.removeEventListener("waiting", handleWaiting)
        video.removeEventListener("playing", handlePlaying)
        document.removeEventListener("fullscreenchange", handleFullscreenChange)
      }

      if (controlsTimeout) {
        clearTimeout(controlsTimeout)
      }
    }
  }, [controlsTimeout])

  // Calculate gradient based on primary color
  const getGradient = () => {
    return `linear-gradient(135deg, ${primaryColorState}80, ${secondaryColorState}80)`
  }

  return (
    <div
      ref={playerRef}
      className="relative w-full max-w-4xl mx-auto overflow-hidden rounded-xl aspect-video group shadow-2xl"
      onMouseMove={handleMouseMove}
      style={
        {
          "--primary-color": primaryColorState,
          "--secondary-color": secondaryColorState,
          "--gradient": getGradient(),
        } as React.CSSProperties
      }
    >
      {/* Video */}
      <video ref={videoRef} src={src} poster={poster} className="w-full h-full object-cover" onClick={togglePlay} />

      {/* Play/Pause overlay */}
      <div
        className={cn(
          "absolute inset-0 flex items-center justify-center bg-black/10 backdrop-blur-sm transition-opacity duration-500",
          isPlaying ? "opacity-0 pointer-events-none" : "opacity-100",
        )}
        onClick={togglePlay}
      >
        <div
          className="w-24 h-24 flex items-center justify-center rounded-full bg-gradient-to-br from-white/30 to-white/10 backdrop-blur-md text-white transition-all duration-300 hover:scale-110 border border-white/20 shadow-lg"
          style={{ background: "var(--gradient)" }}
        >
          <Play className="w-12 h-12 fill-white ml-2" />
        </div>
      </div>

      {/* Buffering indicator */}
      {isBuffering && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-sm">
          <div className="w-16 h-16 rounded-full border-4 border-white/20 border-t-white animate-spin"></div>
        </div>
      )}

      {/* Title bar */}
      <div
        className={cn(
          "absolute inset-x-0 top-0 p-4 bg-gradient-to-b from-black/70 to-transparent transition-opacity duration-300",
          showControls ? "opacity-100" : "opacity-0",
        )}
      >
        <h2 className="text-white text-xl font-bold drop-shadow-md">{title}</h2>
      </div>

      {/* Time preview on hover */}
      {hoverPosition !== null && previewTime !== null && (
        <div
          className="absolute bottom-16 px-3 py-1 rounded-md bg-black/80 text-white text-sm transform -translate-x-1/2 backdrop-blur-md"
          style={{ left: `${hoverPosition * 100}%` }}
        >
          {formatTime(previewTime)}
        </div>
      )}

      {/* Controls */}
      <div
        className={cn(
          "absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/80 via-black/50 to-transparent p-6 transition-all duration-500 backdrop-blur-sm",
          showControls ? "opacity-100 translate-y-0" : "opacity-0 translate-y-10",
        )}
      >
        {/* Progress bar */}
        <div
          className="mb-4 relative h-2 group/progress"
          ref={progressRef}
          onMouseMove={handleProgressHover}
          onMouseLeave={handleProgressLeave}
        >
          <div className="absolute inset-0 bg-white/20 rounded-full overflow-hidden">
            <div
              className="h-full rounded-full transition-all duration-100 ease-out"
              style={{
                width: `${(currentTime / duration) * 100}%`,
                background: `linear-gradient(to right, ${primaryColorState}, ${secondaryColorState})`,
              }}
            ></div>
          </div>
          <div
            className="absolute top-1/2 w-4 h-4 rounded-full bg-white shadow-md -translate-y-1/2 -ml-2 opacity-0 group-hover/progress:opacity-100 transition-opacity duration-200"
            style={{
              left: `${(currentTime / duration) * 100}%`,
              background: primaryColorState,
            }}
          ></div>
          <Slider
            value={[currentTime]}
            min={0}
            max={duration || 100}
            step={0.1}
            onValueChange={handleSeek}
            className="absolute inset-0 cursor-pointer opacity-0"
          />
        </div>

        {/* Controls row */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            {/* Play/Pause button */}
            <Button
              variant="ghost"
              size="icon"
              onClick={togglePlay}
              className="text-white hover:bg-white/10 rounded-full w-10 h-10 transition-transform duration-200 hover:scale-110"
            >
              {isPlaying ? (
                <Pause className="w-5 h-5 transition-all duration-200" />
              ) : (
                <Play className="w-5 h-5 ml-0.5 transition-all duration-200" />
              )}
            </Button>

            {/* Skip buttons */}
            <Button
              variant="ghost"
              size="icon"
              onClick={() => skip(-10)}
              className="text-white hover:bg-white/10 rounded-full w-10 h-10 transition-transform duration-200 hover:scale-110"
            >
              <SkipBack className="w-5 h-5" />
            </Button>

            <Button
              variant="ghost"
              size="icon"
              onClick={() => skip(10)}
              className="text-white hover:bg-white/10 rounded-full w-10 h-10 transition-transform duration-200 hover:scale-110"
            >
              <SkipForward className="w-5 h-5" />
            </Button>

            {/* Volume control */}
            <div className="flex items-center gap-2 group/volume">
              <Button
                variant="ghost"
                size="icon"
                onClick={toggleMute}
                className="text-white hover:bg-white/10 rounded-full w-10 h-10 transition-transform duration-200 hover:scale-110"
              >
                {isMuted ? <VolumeX className="w-5 h-5" /> : <Volume2 className="w-5 h-5" />}
              </Button>

              <div className="w-0 overflow-hidden transition-all duration-300 group-hover/volume:w-20">
                <Slider
                  value={[isMuted ? 0 : volume]}
                  min={0}
                  max={1}
                  step={0.01}
                  onValueChange={handleVolumeChange}
                  className="w-20"
                  styles={{
                    track: {
                      backgroundColor: "rgba(255, 255, 255, 0.2)",
                    },
                    range: {
                      background: `linear-gradient(to right, ${primaryColorState}, ${secondaryColorState})`,
                    },
                    thumb: {
                      backgroundColor: "white",
                      borderColor: primaryColorState,
                    },
                  }}
                />
              </div>
            </div>

            {/* Time display */}
            <div className="text-white text-sm font-medium">
              {formatTime(currentTime)} / {formatTime(duration)}
            </div>
          </div>

          <div className="flex items-center gap-3">
            {/* Settings */}
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  className="text-white hover:bg-white/10 rounded-full w-10 h-10 transition-transform duration-200 hover:scale-110"
                >
                  <Settings className="w-5 h-5" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-80 backdrop-blur-lg bg-black/70 border-white/20 text-white">
                <Tabs defaultValue="colors" className="w-full">
                  <TabsList className="grid w-full grid-cols-1 bg-white/10 text-white">
                    <TabsTrigger value="colors" className="data-[state=active]:bg-white/20">
                      Colors
                    </TabsTrigger>
                  </TabsList>
                  <TabsContent value="colors" className="space-y-4 mt-2">
                    <div className="space-y-2">
                      <label className="text-sm font-medium">Primary Color</label>
                      <div className="flex items-center gap-2">
                        <input
                          type="color"
                          value={primaryColorState}
                          onChange={(e) => setPrimaryColorState(e.target.value)}
                          className="w-10 h-10 rounded-full cursor-pointer border-2 border-white/20"
                        />
                        <input
                          type="text"
                          value={primaryColorState}
                          onChange={(e) => setPrimaryColorState(e.target.value)}
                          className="flex h-9 w-full rounded-md border border-white/20 bg-white/10 px-3 py-1 text-sm shadow-sm"
                        />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-sm font-medium">Secondary Color</label>
                      <div className="flex items-center gap-2">
                        <input
                          type="color"
                          value={secondaryColorState}
                          onChange={(e) => setSecondaryColorState(e.target.value)}
                          className="w-10 h-10 rounded-full cursor-pointer border-2 border-white/20"
                        />
                        <input
                          type="text"
                          value={secondaryColorState}
                          onChange={(e) => setSecondaryColorState(e.target.value)}
                          className="flex h-9 w-full rounded-md border border-white/20 bg-white/10 px-3 py-1 text-sm shadow-sm"
                        />
                      </div>
                    </div>
                    <div className="pt-2">
                      <div
                        className="w-full h-10 rounded-md"
                        style={{
                          background: `linear-gradient(to right, ${primaryColorState}, ${secondaryColorState})`,
                        }}
                      ></div>
                    </div>
                  </TabsContent>
                </Tabs>
              </PopoverContent>
            </Popover>

            {/* Fullscreen button */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleFullscreen}
              className="text-white hover:bg-white/10 rounded-full w-10 h-10 transition-transform duration-200 hover:scale-110"
            >
              {isFullscreen ? <Minimize className="w-5 h-5" /> : <Maximize className="w-5 h-5" />}
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}
